#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    int is_leaf;
    int num_keys;
} knode;

__kernel void kernel_cpu(
    const int cores_arg,
    __global record *records,
    __global knode *knodes,
    const long knodes_elem,
    const int order,
    const long maxheight,
    const int count,
    __global long *currKnode,
    __global long *offset,
    __global int *keys,
    __global record *ans)
{
    int threadsPerBlock = order < 1024 ? order : 1024;
    int global_id = get_global_id(0);
    int bid = global_id / threadsPerBlock;
    int thid = global_id % threadsPerBlock;

    if (bid >= count) return;

    for (long i = 0; i < maxheight; i++) {
        barrier(CLK_GLOBAL_MEM_FENCE);
        if (thid < threadsPerBlock) {
            int key_left = knodes[currKnode[bid]].keys[thid];
            int key_right = knodes[currKnode[bid]].keys[thid + 1];
            int key = keys[bid];
            if (key_left <= key && key_right > key) {
                int idx = knodes[offset[bid]].indices[thid];
                if (idx < knodes_elem) {
                    offset[bid] = idx;
                }
            }
        }
        barrier(CLK_GLOBAL_MEM_FENCE);
        if (thid == 0) {
            currKnode[bid] = offset[bid];
        }
        barrier(CLK_GLOBAL_MEM_FENCE);
    }

    barrier(CLK_GLOBAL_MEM_FENCE);

    if (thid < threadsPerBlock) {
        int key = keys[bid];
        if (knodes[currKnode[bid]].keys[thid] == key) {
            ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
        }
    }
}

